-- sticker-stage3-tattoo-fix.sql — 타투 기본가 2000 반영 (사장님 도메인 확정 2026-06-28)
-- 규칙: 총액(q장) = 2000(기본·1회) + 4000×(q/3). q∈{3,6,...,999}·incr=3 → .02 밴드별 총액.
-- 엔진 .02: (unit_price ÷ 구간min_qty) × 수량. q가 항상 밴드 min_qty와 일치 → unit=총액이 정확.
\set ON_ERROR_STOP on
BEGIN;
DROP TABLE IF EXISTS bak_sticker_tattoo_260628;
CREATE TABLE bak_sticker_tattoo_260628 AS SELECT * FROM t_prc_component_prices WHERE comp_cd='COMP_STK_TATTOO';
SELECT setval('public.t_prc_component_prices_comp_price_id_seq',(SELECT max(comp_price_id) FROM t_prc_component_prices), true);
-- min3: 4000 → 6000(2000기본+4000)
UPDATE t_prc_component_prices SET unit_price=6000, note='타투 3장세트 기본가2000+4000·260628'
 WHERE comp_cd='COMP_STK_TATTOO' AND siz_cd='SIZ_000060' AND mat_cd='MAT_000167' AND min_qty=3;
