-- 어서션: 엔진 .02 재현 (band=max min_qty≤q · total=(unit/band)*q)
\echo '== 타투 골든 재계산 (3=6000·6=10000·9=14000·30=42000·300=402000) =='
SELECT q, (SELECT unit_price FROM t_prc_component_prices cp WHERE cp.comp_cd='COMP_STK_TATTOO' AND cp.min_qty=(
            SELECT max(min_qty) FROM t_prc_component_prices c2 WHERE c2.comp_cd='COMP_STK_TATTOO' AND c2.min_qty<=q))
         * q / (SELECT max(min_qty) FROM t_prc_component_prices c3 WHERE c3.comp_cd='COMP_STK_TATTOO' AND c3.min_qty<=q) AS engine_total,
       2000+4000*(q/3) AS expected
FROM (VALUES (3),(6),(9),(30),(300),(999)) AS t(q);
